import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { CheckCircle, TrendingUp } from 'lucide-react';
import './ValidationChart.css';

function ValidationChart({ apiUrl }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadValidationData();
  }, []);

  const loadValidationData = async () => {
    try {
      const response = await axios.get(`${apiUrl}/api/validation-results`);
      setData(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error loading validation data:', error);
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="validation-chart">
        <div className="card">
          <p>Loading validation results...</p>
        </div>
      </div>
    );
  }

  if (!data) {
    return (
      <div className="validation-chart">
        <div className="card">
          <p>No validation data available.</p>
        </div>
      </div>
    );
  }

  const chartData = data.stations.map(station => ({
    name: station.name,
    Real: station.real,
    Twin: station.twin
  }));

  return (
    <div className="validation-chart">
      <div className="card validation-header">
        <div className="accuracy-badge-large">
          <CheckCircle size={48} />
          <div>
            <div className="accuracy-value">{data.accuracy}%</div>
            <div className="accuracy-label">Validation Accuracy</div>
          </div>
        </div>
        <div className="validation-stats">
          <div className="stat-item">
            <span className="stat-label">Overall Error</span>
            <span className="stat-value">{data.overall_error}%</span>
          </div>
          <div className="stat-item">
            <span className="stat-label">Stations Validated</span>
            <span className="stat-value">{data.stations.length}</span>
          </div>
        </div>
      </div>

      <div className="card">
        <h2 className="card-title">Real vs Digital Twin Comparison</h2>
        <p className="subtitle">
          Mean service times across all stations. The twin closely matches real-world behavior.
        </p>

        <ResponsiveContainer width="100%" height={400}>
          <BarChart data={chartData} margin={{ top: 20, right: 30, left: 20, bottom: 60 }}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis
              dataKey="name"
              angle={-45}
              textAnchor="end"
              height={100}
              style={{ fontSize: '0.85rem' }}
            />
            <YAxis
              label={{ value: 'Mean Processing Time (s)', angle: -90, position: 'insideLeft' }}
              style={{ fontSize: '0.85rem' }}
            />
            <Tooltip
              contentStyle={{
                background: 'rgba(255, 255, 255, 0.95)',
                border: '2px solid #667eea',
                borderRadius: '8px'
              }}
            />
            <Legend
              wrapperStyle={{ paddingTop: '20px' }}
            />
            <Bar dataKey="Real" fill="#4c72b0" name="Real Factory" />
            <Bar dataKey="Twin" fill="#55a868" name="Digital Twin" />
          </BarChart>
        </ResponsiveContainer>
      </div>

      <div className="card">
        <h3>Station-by-Station Error Analysis</h3>
        <div className="error-table">
          <div className="table-header">
            <div>Station</div>
            <div>Real (s)</div>
            <div>Twin (s)</div>
            <div>Error %</div>
          </div>
          {data.stations.map((station, idx) => (
            <div key={idx} className="table-row">
              <div className="station-name">{station.name}</div>
              <div>{station.real.toFixed(2)}</div>
              <div>{station.twin.toFixed(2)}</div>
              <div>
                <span className={`error-badge ${station.error < 1 ? 'excellent' : 'good'}`}>
                  {station.error.toFixed(2)}%
                </span>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="card breakthrough-card">
        <TrendingUp size={32} className="breakthrough-icon" />
        <h3>The Breakthrough: Data Cleaning</h3>
        <div className="breakthrough-content">
          <div className="breakthrough-stat">
            <div className="big-number">18,000+</div>
            <p>Zero-second artifacts discovered and filtered from raw logs</p>
          </div>
          <div className="breakthrough-stat">
            <div className="big-number">66% → 0.27%</div>
            <p>Error reduction after implementing intelligent data filtering</p>
          </div>
        </div>
        <p className="breakthrough-desc">
          Our validation script identified logging errors where START and COMPLETE events 
          occurred simultaneously, creating impossible zero-duration records. By filtering 
          these artifacts (duration &gt; 0.001s), we revealed the twin's true accuracy.
        </p>
      </div>

      <div className="card methodology-card">
        <h3>Validation Methodology</h3>
        <ol className="methodology-list">
          <li>
            <strong>Trace-Driven Simulation:</strong> The twin replays exact historical arrival times 
            from the real factory, ensuring a fair comparison.
          </li>
          <li>
            <strong>Active Processing Time Only:</strong> We compare only actual processing duration, 
            excluding queue waiting times which depend on arrival patterns.
          </li>
          <li>
            <strong>Data Cleaning:</strong> Invalid zero-second records are filtered out to prevent 
            corruption of statistical measures.
          </li>
          <li>
            <strong>Mean Comparison:</strong> We validate that the twin's average behavior matches 
            reality across all stations.
          </li>
        </ol>
      </div>
    </div>
  );
}

export default ValidationChart;
